    verify_resp = requests.get(
        BASE_URL,
        params={"subject": "Patient/p-002"},
        headers=<admin_headers_fixture>()
    )
    assert verify_resp.json().get("total", 0) == 0

import pytest
import requests

BASE_URL = "http://fhir-lite/ServiceRequest"

@pytest.fixture
def clinician_headers():
    return <auth_fixture>(role="clinician")

@pytest.fixture
def payload_missing_code():
    payload = <build_service_request_payload>(
        subject="Patient/p-003",
        requester="Practitioner/prac-001",
        performer="Organization/LabCorp"
    )
    payload.pop("code", None)
    return payload

def test_lab_order_rejected_when_mandatory_code_missing(clinician_headers, payload_missing_code):
    resp = requests.post(BASE_URL, json=payload_missing_code, headers=clinician_headers)
    assert resp.status_code == 422
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    diagnostics = " ".join(i.get("diagnostics", "") for i in issues)
    assert "code" in diagnostics.lower()

import pytest
import requests

BASE_URL = "http://fhir-lite/ServiceRequest"

@pytest.fixture
def clinician_headers():
    return <auth_fixture>(role="clinician")

@pytest.fixture
def revoked_order_id(clinician_headers):
    order_id = <create_and_cancel_order>(
        subject="Patient/p-004",
        code="58410-2",
        headers=clinician_headers
    )
    return order_id

def test_cancelling_already_cancelled_order_rejected(clinician_headers, revoked_order_id):
    patch_body = {"resourceType": "ServiceRequest", "id": revoked_order_id, "status": "revoked"}
    resp = requests.patch(
        f"{BASE_URL}/{revoked_order_id}",
        json=patch_body,
        headers=clinician_headers
    )
    assert resp.status_code in (409, 422)
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    get_resp = requests.get(f"{BASE_URL}/{revoked_order_id}", headers=clinician_headers)
    assert get_resp.json()["status"] == "revoked"

import pytest
import requests

BASE_URL = "http://fhir-lite/ServiceRequest"

@pytest.fixture(autouse=True)
def mark_labcorp_unavailable():
    <set_lab_availability>(lab="LabCorp", available=False)
    yield
    <set_lab_availability>(lab="LabCorp", available=True)

@pytest.fixture
def clinician_headers():
    return <auth_fixture>(role="clinician")

@pytest.fixture
def preferred_lab_payload():
    return <build_service_request_payload>(
        subject="Patient/p-005",
        code="58410-2",
        requester="Practitioner/prac-001",
        performer="Organization/LabCorp"
    )

def test_lab_order_falls_back_to_default_when_preferred_unavailable(clinician_headers, preferred_lab_payload):
    resp = requests.post(BASE_URL, json=preferred_lab_payload, headers=clinician_headers)
    assert resp.status_code == 201
    body = resp.json()
    assert body["status"] == "active"
    performers = [p["reference"] for p in body.get("performer", [])]
    assert any("DefaultLab" in p for p in performers)
    assert not any("LabCorp" in p for p in performers)
    extensions = body.get("extension", [])
    notes = body.get("note", [])
    fallback_indicated = (
        any("unavailable" in str(e).lower() for e in extensions) or
        any("unavailable" in str(n).lower() for n in notes)
    )
    assert fallback_indicated
    <teardown_resource>(resp.headers["Location"], clinician_headers)
